import pytest
import requests
import os

BASE_URL = os.environ.get("BANKING_API_URL", "http://localhost:8080")

@pytest.fixture
def unverified_customer_token():
    return <fixture: unverified_customer_token>

def test_open_savings_account_unverified_customer_rejected(unverified_customer_token):
    headers = {"Authorization": f"Bearer {unverified_customer_token}"}
    payload = {"initial_deposit": 500.00}
    resp = requests.post(f"{BASE_URL}/accounts/savings", json=payload, headers=headers)
    assert resp.status_code in (403, 422)
    body = resp.json()
    error_text = str(body.get("error", body.get("detail", ""))).lower()
    assert "verif" in error_text or "forbidden" in error_text or "not allowed" in error_text
